use aiken/collection/list
use aiken/interval
use cardano/address.{Credential, VerificationKey}
use cardano/governance.{ConstitutionalCommitteeMember, DelegateRepresentative, StakePool, Voter}
use cardano/transaction.{Transaction}

/// Período de validez para votar
pub type VotingPeriod {
  /// Tiempo mínimo (slot) desde el cual se permite votar
  valid_from: Int,
  /// Tiempo máximo (slot) hasta el cual se permite votar
  valid_until: Int,
  /// Clave pública del votante autorizado
  authorized_signer: ByteArray,
}

validator time_locked_vote {
  vote(redeemer: VotingPeriod, voter: Voter, self: Transaction) -> Bool {
    let VotingPeriod { valid_from, valid_until, authorized_signer } = redeemer

    // 1. Construir el intervalo permitido para votar
    let allowed_period =
      interval.between(valid_from, valid_until)

    // 2. Verificar que el rango de validez de la transacción esté
    //    completamente contenido dentro del período permitido.
    let within_period =
      interval.hull(allowed_period, self.validity_range) == allowed_period

    // 3. Verificar que el votante autorizado haya firmado la transacción
    let is_signed =
      list.has(self.extra_signatories, authorized_signer)

    // 4. Verificar que el voter corresponda al firmante autorizado.
    let voter_matches =
      when voter is {
        ConstitutionalCommitteeMember(cred) ->
          when cred is {
            VerificationKey(vkh) -> vkh == authorized_signer
            _ -> False
          }
        DelegateRepresentative(credential) ->
          when credential is {
            VerificationKey(vkh) -> vkh == authorized_signer
            _ -> False
          }
        StakePool(pool_id) ->
          pool_id == authorized_signer
      }

    // Todas las condiciones deben cumplirse
    and {
      within_period?,
      is_signed?,
      voter_matches?,
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/address.{Credential, VerificationKey}
use cardano/governance.{
  ConstitutionalCommitteeMember,
  DelegateRepresentative,
  StakePool,
  Voter,
}
use cardano/transaction.{Transaction}
use aiken/crypto.{VerificationKeyHash}

/// Tipo del redeemer: el usuario indica si quiere votar Yes o No.
pub type VoteChoice {
  VoteYes
  VoteNo
}

validator drep_vote_validator {
  vote(redeemer: VoteChoice, voter: Voter, self: Transaction) -> Bool {
    // 1. Verificar que el votante sea un DelegateRepresentative
    //    y extraer su credencial.
    let drep_credential: Credential =
      when voter is {
        DelegateRepresentative(cred) -> cred
        ConstitutionalCommitteeMember(_) -> fail @"Solo DReps pueden usar este validador"
        StakePool(_) -> fail @"Solo DReps pueden usar este validador"
      }

    // 2. Extraer el VerificationKeyHash de la credencial del DRep.
    //    Solo aceptamos credenciales basadas en clave de verificación.
    let drep_vkh: ByteArray =
      when drep_credential is {
        VerificationKey(hash) -> hash
        _ -> fail @"La credencial del DRep debe ser una clave de verificación"
      }

    // 3. Verificar que la firma del DRep esté presente en extra_signatories.
    let drep_signed: Bool =
      list.has(self.extra_signatories, drep_vkh)

    // 4. Validar que efectivamente firmó.
    expect drep_signed == True

    // 5. Verificar que el redeemer sea un voto válido (Yes o No).
    //    Ambos son aceptados; lo importante es que el DRep firmó.
    when redeemer is {
      VoteYes -> True
      VoteNo -> True
    }
  }

  else(_) {
    fail
  }
}

