  }
}

use aiken/collection/list
use cardano/address.{Credential, Script, VerificationKey}
use cardano/governance.{
  ConstitutionalCommitteeMember, DelegateRepresentative, StakePool, Voter,
}
use cardano/transaction.{Transaction}
use aiken/crypto.{VerificationKeyHash}

/// Lista de credenciales autorizadas para votar, proporcionada como parámetro.
pub type AuthorizedVoters {
  voters: List<VerificationKeyHash>,
}

/// El redeemer no necesita datos adicionales en este caso.
pub type VoteRedeemer {
  /// Justificación opcional del voto
  justification: ByteArray,
}

/// Extrae el VerificationKeyHash de un Voter, si es posible.
fn get_voter_key_hash(voter: Voter) -> Option<VerificationKeyHash> {
  when voter is {
    ConstitutionalCommitteeMember(credential) ->
      when credential is {
        VerificationKey(hash) -> Some(hash)
        Script(_) -> None
      }
    DelegateRepresentative(credential) ->
      when credential is {
        VerificationKey(hash) -> Some(hash)
        Script(_) -> None
      }
    StakePool(pool_id) -> Some(pool_id)
  }
}

/// Verifica si un VerificationKeyHash está en la lista de autorizados.
fn is_authorized(
  key_hash: VerificationKeyHash,
  authorized: List<VerificationKeyHash>,
) -> Bool {
  list.has(authorized, key_hash)
}

/// Verifica si un VerificationKeyHash firmó la transacción.
fn has_signed(
  key_hash: VerificationKeyHash,
  signatories: List<VerificationKeyHash>,
) -> Bool {
  list.has(signatories, key_hash)
}

validator authorized_vote(config: AuthorizedVoters) {
  vote(redeemer: VoteRedeemer, voter: Voter, self: Transaction) {
    // Paso 1: Extraer la clave del votante
    expect Some(voter_key_hash) = get_voter_key_hash(voter)

    // Paso 2: Verificar que el votante está en la lista de autorizados
    let voter_is_authorized = is_authorized(voter_key_hash, config.voters)

    // Paso 3: Verificar que el votante firmó la transacción
    let voter_has_signed = has_signed(voter_key_hash, self.extra_signatories)

    // Paso 4: Verificar que el redeemer no está vacío (justificación requerida)
    let has_justification = redeemer.justification != ""

    // Todas las condiciones deben cumplirse
    and {
      voter_is_authorized?,
      voter_has_signed?,
      has_justification?,
    }
  }

  else(_) {
    fail
  }
}

