use aiken/collection/list
use cardano/address.{Credential, Script, VerificationKey}
use cardano/governance.{
  ConstitutionalCommitteeMember,
  DelegateRepresentative,
  StakePool,
  Voter,
}
use cardano/transaction.{Transaction}

pub type VoteChoice {
  VoteYes
  VoteNo
  VoteAbstain
}

pub type VoteAction {
  expected_vote: VoteChoice,
  required_signer: Option<ByteArray>,
}

fn has_signed(signatories: List<ByteArray>, vkh: ByteArray) -> Bool {
  list.has(signatories, vkh)
}

validator voter_dispatch {
  vote(redeemer: VoteAction, voter: Voter, self: Transaction) {
    let signatories = self.extra_signatories

    let additional_signer_ok =
      when redeemer.required_signer is {
        None -> True
        Some(signer) -> has_signed(signatories, signer)
      }

    let voter_authorized =
      when voter is {
        ConstitutionalCommitteeMember(hot_credential) ->
          when hot_credential is {
            VerificationKey(vkh) -> has_signed(signatories, vkh)
            Script(_script_hash) ->
              when redeemer.required_signer is {
                Some(signer) -> has_signed(signatories, signer)
                None -> False
              }
          }

        DelegateRepresentative(drep_credential) ->
          when drep_credential is {
            VerificationKey(vkh) -> has_signed(signatories, vkh)
            Script(_script_hash) ->
              when redeemer.required_signer is {
                Some(signer) -> has_signed(signatories, signer)
                None -> False
              }
          }

        StakePool(pool_id) -> has_signed(signatories, pool_id)
      }

    let vote_policy_ok =
      when voter is {
        StakePool(_) ->
          when redeemer.expected_vote is {
            VoteYes -> True
            VoteNo -> True
            VoteAbstain -> False
          }
        ConstitutionalCommitteeMember(_) ->
          when redeemer.expected_vote is {
            VoteYes -> True
            VoteNo -> True
            VoteAbstain -> False
          }
        DelegateRepresentative(_) ->
          when redeemer.expected_vote is {
            VoteYes -> True
            VoteNo -> True
            VoteAbstain -> True
          }
      }

    and {
      additional_signer_ok,
      voter_authorized,
      vote_policy_ok,
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/address.{Credential, Script, VerificationKey}
use cardano/governance.{
  ConstitutionalCommitteeMember,
  DelegateRepresentative,
  StakePool,
  Voter,
}
use cardano/transaction.{Transaction}

/// El datum que almacena el hash de clave del DRep autorizado.
/// Se usa `ByteArray` para representar el hash de la clave de verificación
/// o el hash del script del DRep.
pub type DRepDatum {
  /// Hash de la credencial del DRep autorizado para votar
  authorized_drep_hash: ByteArray,
}

validator drep_vote_validator {
  /// Handler de voto: verifica que el voter sea el DRep autorizado
  /// cuyo hash de credencial coincide con el almacenado en el datum.
  ///
  /// - `datum`: contiene el hash del DRep autorizado.
  /// - `voter`: el Voter que intenta emitir el voto.
  /// - `self`: la transacción completa para inspecciones adicionales.
  vote(datum: DRepDatum, voter: Voter, self: Transaction) -> Bool {
    // Extraemos el hash autorizado del datum
    let authorized_hash = datum.authorized_drep_hash

    // Verificamos que el voter sea un DelegateRepresentative
    // y que su credencial coincida con el hash autorizado
    when voter is {
      DelegateRepresentative(credential) ->
        when credential is {
          // Si la credencial es una clave de verificación,
          // comparamos su hash con el autorizado
          VerificationKey(vk_hash) -> vk_hash == authorized_hash
          // Si la credencial es un script,
          // comparamos su hash con el autorizado
          Script(script_hash) -> script_hash == authorized_hash
        }

      // Si el voter es un miembro del Comité Constitucional
      // o un operador de stake pool, rechazamos
      ConstitutionalCommitteeMember(_) -> fail @"Solo DReps autorizados pueden votar"
      StakePool(_) -> fail @"Solo DReps autorizados pueden votar"
    }
  }

  // Fallback obligatorio para otros handlers
  else(_) {
    fail
  }
}

