/// The deadline is a POSIX timestamp (milliseconds) after which
/// deregistration is permitted.
pub type Deadline =
  Int

validator deregister_after_deadline {
  publish(redeemer: Deadline, cert: Certificate, self: Transaction) -> Bool {
    when cert is {
      UnregisterCredential { credential: _, refund: _ } -> {
        // The deadline from the redeemer
        let deadline: Int = redeemer

        // Ensure the transaction's validity range starts strictly after the deadline.
        // This means the lower bound of the validity range must be greater than the deadline.
        let valid_after_deadline =
          interval.is_entirely_after(self.validity_range, deadline)

        valid_after_deadline
      }
      _ -> fail @"Only UnregisterCredential certificates are allowed"
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
