use cardano/transaction.{Transaction}

validator credential_manager {
  publish(redeemer: Data, cert: Certificate, self: Transaction) -> Bool {
    when cert is {
      RegisterCredential { credential, deposit } -> {
        // Registration is freely allowed; no additional checks needed.
        // We reference deposit to avoid unused-variable warnings.
        let _ = deposit
        let _ = credential
        True
      }

      UnregisterCredential { credential, refund } -> {
        // Unregistration requires that the credential owner signed the tx.
        let _ = refund
        when credential is {
          VerificationKey(vkh) ->
            list.has(self.extra_signatories, vkh)
          _ ->
            // For script credentials, we rely on the script being invoked
            // elsewhere in the transaction. Here we simply allow it.
            True
        }
      }

      _ -> fail @"Only RegisterCredential and UnregisterCredential are supported"
    }
  }

  else(_) {
    fail
  }
}

