use aiken/collection/list
use aiken/interval.{Finite, Interval, IntervalBound}
use cardano/certificate.{Certificate}
use cardano/transaction.{Transaction}

/// Datum that defines the permitted time window for certificate operations.
pub type TimeWindowDatum {
  /// Earliest POSIX time (in milliseconds) when certificates are allowed.
  valid_from: Int,
  /// Latest POSIX time (in milliseconds) when certificates are allowed.
  valid_to: Int,
}

/// Checks that the transaction's validity range is entirely contained
/// within the [valid_from, valid_to] window.
fn validity_range_within_window(
  validity_range: Interval,
  valid_from: Int,
  valid_to: Int,
) -> Bool {
  // The transaction's lower bound must be at or after valid_from
  let lower_ok =
    when validity_range.lower_bound.bound_type is {
      Finite(lo) -> lo >= valid_from
      _ -> False
    }

  // The transaction's upper bound must be at or before valid_to
  let upper_ok =
    when validity_range.upper_bound.bound_type is {
      Finite(hi) -> hi <= valid_to
      _ -> False
    }

  lower_ok && upper_ok
}

validator time_window_publish {
  publish(
    datum: TimeWindowDatum,
    _cert: Certificate,
    self: Transaction,
  ) -> Bool {
    // Ensure the transaction validity range falls within the permitted window
    validity_range_within_window(
      self.validity_range,
      datum.valid_from,
      datum.valid_to,
    )
  }

  else(_) {
    fail
  }
}

