/// The datum attached to UTxOs locked at this validator.
/// It stores the owner's verification key hash.
pub type SpendDatum {
  owner: ByteArray,
}

/// Redeemer for the spend handler — unit-style, no extra data needed.
pub type SpendRedeemer {
  SpendAction
}

/// Redeemer for the publish handler.
pub type PublishRedeemer {
  PublishAction
}

validator multi_handler {
  /// Spend handler: ensures the owner listed in the datum has signed the transaction.
  spend(
    datum: Option<SpendDatum>,
    _redeemer: SpendRedeemer,
    _output_reference: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      Some(d) -> {
        let owner_vkh = d.owner
        list.has(self.extra_signatories, owner_vkh)
      }
      None -> fail @"Missing datum: UTxO must carry a SpendDatum"
    }
  }

  /// Publish handler: only permits RegisterCredential and UnregisterCredential certificates.
  publish(
    _redeemer: PublishRedeemer,
    cert: Certificate,
    _self: Transaction,
  ) -> Bool {
    when cert is {
      RegisterCredential { .. } -> True
      UnregisterCredential { .. } -> True
      _ -> fail @"Only RegisterCredential and UnregisterCredential certificates are allowed"
    }
  }

  /// Fallback: reject everything else (mint, withdraw, vote, propose, etc.)
  else(_) {
    fail @"Unsupported handler invocation"
  }
}

use aiken/collection/list
use cardano/address.{Credential, VerificationKey}
use cardano/certificate.{Certificate, RegisterCredential}
use cardano/transaction.{Transaction}

/// The redeemer carries the expected owner's verification key hash.
/// The validator checks that:
/// 1. The certificate is a RegisterCredential for a credential that matches the owner.
/// 2. The owner has signed the transaction.
pub type OwnerRedeemer {
  /// The verification key hash of the expected owner
  owner: ByteArray,
}

validator credential_registration {
  publish(redeemer: OwnerRedeemer, cert: Certificate, self: Transaction) -> Bool {
    let owner_vkh = redeemer.owner

    // Ensure the owner signed the transaction
    let owner_signed =
      list.has(self.extra_signatories, owner_vkh)

    // Match on the certificate to ensure it's a credential registration
    // and that the credential belongs to the owner
    when cert is {
      RegisterCredential { credential, .. } -> {
        let credential_matches_owner =
          when credential is {
            VerificationKey(vkh) -> vkh == owner_vkh
            _ -> False
          }

        // Both conditions must hold
        credential_matches_owner && owner_signed
      }

      // Reject all other certificate types
      _ -> fail @"Only RegisterCredential certificates are allowed"
    }
  }

  else(_) {
    fail
  }
}

