use aiken/collection/list
use cardano/address.{Credential, VerificationKey, Script}
use cardano/certificate.{
  Certificate,
  RegisterAndDelegateCredential,
  UnregisterCredential,
  RegisterCredential,
}
use cardano/transaction.{Transaction}
use aiken/interval.{Finite}

/// Extrae el VerificationKeyHash de una credencial si es de tipo VerificationKey.
/// Retorna None si es una credencial de script.
fn credential_to_vkh(cred: Credential) -> Option<ByteArray> {
  when cred is {
    VerificationKey(vkh) -> Some(vkh)
    Script(_) -> None
  }
}

/// Verifica que un VerificationKeyHash esté entre los firmantes de la transacción.
fn signed_by(signatories: List<ByteArray>, vkh: ByteArray) -> Bool {
  list.has(signatories, vkh)
}

/// Verifica que el límite superior del rango de validez sea finito y menor que un valor dado.
fn validity_before(tx: Transaction, max_slot: Int) -> Bool {
  when tx.validity_range.upper_bound.bound_type is {
    Finite(slot) -> slot < max_slot
    _ -> False
  }
}

validator registration_handler {
  publish(redeemer: Data, cert: Certificate, self: Transaction) -> Bool {
    when cert is {
      // --- REGISTRO DE CREDENCIAL ---
      RegisterCredential { credential, deposit } -> {
        // La credencial debe ser de tipo VerificationKey y debe haber firmado
        expect Some(vkh) = credential_to_vkh(credential)
        let has_signed = signed_by(self.extra_signatories, vkh)

        // Traza para depuración
        trace @"register: verificando firma del propietario"
        has_signed
      }

      // --- DES-REGISTRO DE CREDENCIAL ---
      UnregisterCredential { credential, refund } -> {
        // La credencial debe ser de tipo VerificationKey y debe haber firmado
        expect Some(vkh) = credential_to_vkh(credential)
        let has_signed = signed_by(self.extra_signatories, vkh)

        // Exigimos un deadline: la transacción debe ser válida antes del slot 1_000_000
        let within_deadline = validity_before(self, 1_000_000)

        trace @"unregister: verificando firma y deadline"
        and {
          has_signed,
          within_deadline,
        }
      }

      // --- CUALQUIER OTRO CERTIFICADO: RECHAZADO ---
      _ -> {
        trace @"certificado no soportado"
        fail
      }
    }
  }

  else(_) {
    fail
  }
}

