use aiken/collection/list
use cardano/certificate.{Certificate, RetireStakePool}
use cardano/transaction.{Transaction}

/// Los tres hashes de verificación de los administradores del pool.
/// En producción, reemplazar estos valores con los hashes reales.
const admin_1: ByteArray = #"aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaabb"

const admin_2: ByteArray = #"bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbcc"

const admin_3: ByteArray = #"ccccccccccccccccccccccccccccccccccccccccccccccccccccccdd"

/// Número mínimo de firmas requeridas (2 de 3).
const required_signatures: Int = 2

/// Cuenta cuántos de los administradores han firmado la transacción.
fn count_admin_signatures(signatories: List<ByteArray>) -> Int {
  let admins: List<ByteArray> = [admin_1, admin_2, admin_3]
  list.foldl(
    admins,
    0,
    fn(admin, acc) {
      if list.has(signatories, admin) {
        acc + 1
      } else {
        acc
      }
    },
  )
}

validator multi_sig_pool_retirement {
  publish(redeemer: Data, cert: Certificate, self: Transaction) -> Bool {
    // Solo permitimos certificados de jubilación de stake pool
    when cert is {
      RetireStakePool { stake_pool: _pool_id, at_epoch: _epoch } -> {
        // Contar cuántos de los 3 administradores firmaron
        let admin_count = count_admin_signatures(self.extra_signatories)
        // Exigir al menos 2 de 3 firmas
        admin_count >= required_signatures
      }
      // Cualquier otro tipo de certificado se rechaza
