use cardano/address.{Credential}
use cardano/certificate.{
  Certificate, RegisterCredential, UnregisterCredential, DelegateCredential,
  RegisterAndDelegateCredential, RegisterDelegateRepresentative,
  UnregisterDelegateRepresentative, UpdateDelegateRepresentative,
  AuthorizeConstitutionalCommitteeProxy, RetireFromConstitutionalCommittee,
}
use cardano/transaction.{Transaction}

/// Extrae la credencial de un certificado, si aplica.
fn credential_from_certificate(cert: Certificate) -> Option<Credential> {
  when cert is {
    RegisterCredential { credential, .. } -> Some(credential)
    UnregisterCredential { credential, .. } -> Some(credential)
    DelegateCredential { credential, .. } -> Some(credential)
    RegisterAndDelegateCredential { credential, .. } -> Some(credential)
    RegisterDelegateRepresentative { delegate_representative, .. } -> Some(delegate_representative)
    UnregisterDelegateRepresentative { delegate_representative, .. } -> Some(delegate_representative)
    UpdateDelegateRepresentative { delegate_representative } -> Some(delegate_representative)
    AuthorizeConstitutionalCommitteeProxy { constitutional_committee_member, .. } ->
      Some(constitutional_committee_member)
    RetireFromConstitutionalCommittee { constitutional_committee_member } -> Some(constitutional_committee_member)
    _ -> None
  }
}

/// Validador parametrizado con la credencial esperada.
/// Solo permite publicar certificados cuya credencial interna
/// coincida con `expected_credential`.
validator credential_publish(expected_credential: Credential) {
  publish(_redeemer: Data, cert: Certificate, _self: Transaction) -> Bool {
    when credential_from_certificate(cert) is {
      Some(cert_credential) -> cert_credential == expected_credential
      None -> fail @"Certificado no contiene una credencial reconocida"
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use aiken/interval.{Finite, Interval, IntervalBound}
use cardano/certificate.{Certificate}
use cardano/transaction.{Transaction}

/// Estructura que define la ventana de tiempo permitida para operaciones de certificado.
/// - `window_start`: inicio de la ventana (POSIX time en milisegundos)
/// - `window_end`: fin de la ventana (POSIX time en milisegundos)
pub type TimeWindow {
  window_start: Int,
  window_end: Int,
}

/// Tipo de redeemer que permite especificar una razón o simplemente actuar.
pub type CertAction {
  Proceed
}

/// Verifica que el rango de validez de la transacción esté completamente
/// contenido dentro de la ventana de tiempo permitida.
fn tx_within_window(validity_range: Interval, window: TimeWindow) -> Bool {
  // Extraer el límite inferior del rango de validez
  let lower_bound_ok =
    when validity_range.lower_bound.bound_type is {
      Finite(lo) -> lo >= window.window_start
      _ -> False
    }

  // Extraer el límite superior del rango de validez
  let upper_bound_ok =
    when validity_range.upper_bound.bound_type is {
      Finite(hi) -> hi <= window.window_end
      _ -> False
    }

  lower_bound_ok && upper_bound_ok
}

validator time_gated_publish(window: TimeWindow) {
  publish(redeemer: CertAction, _certificate: Certificate, self: Transaction) -> Bool {
    // Verificar que la transacción ocurre dentro de la ventana de tiempo
    let is_within_window = tx_within_window(self.validity_range, window)

    // Si no está dentro de la ventana, rechazar
    when redeemer is {
      Proceed -> is_within_window
    }
  }

  else(_) {
    fail
  }
}

test tx_within_window_exact_bounds() {
  let window = TimeWindow { window_start: 1_000_000, window_end: 2_000_000 }
  let validity_range =
    Interval {
      lower_bound: IntervalBound { bound_type: Finite(1_000_000), is_inclusive: True },
      upper_bound: IntervalBound { bound_type: Finite(2_000_000), is_inclusive: True },
    }
  tx_within_window(validity_range, window) == True
}

test tx_within_window_strictly_inside() {
  let window = TimeWindow { window_start: 1_000_000, window_end: 5_000_000 }
  let validity_range =
    Interval {
      lower_bound: IntervalBound { bound_type: Finite(1_500_000), is_inclusive: True },
      upper_bound: IntervalBound { bound_type: Finite(4_500_000), is_inclusive: True },
    }
  tx_within_window(validity_range, window) == True
}

test tx_within_window_lower_too_early() {
  let window = TimeWindow { window_start: 1_000_000, window_end: 2_000_000 }
  let validity_range =
    Interval {
      lower_bound: IntervalBound { bound_type: Finite(999_999), is_inclusive: True },
      upper_bound: IntervalBound { bound_type: Finite(1_500_000), is_inclusive: True },
    }
  tx_within_window(validity_range, window) == False
}

test tx_within_window_upper_too_late() {
  let window = TimeWindow { window_start: 1_000_000, window_end: 2_000_000 }
  let validity_range =
    Interval {
      lower_bound: IntervalBound { bound_type: Finite(1_500_000), is_inclusive: True },
      upper_bound: IntervalBound { bound_type: Finite(2_000_001), is_inclusive: True },
    }
  tx_within_window(validity_range, window) == False
}

test tx_within_window_negative_infinity_lower_fails() {
  let window = TimeWindow { window_start: 1_000_000, window_end: 2_000_000 }
  let validity_range =
    Interval {
      lower_bound: IntervalBound { bound_type: interval.NegativeInfinity, is_inclusive: False },
      upper_bound: IntervalBound { bound_type: Finite(1_500_000), is_inclusive: True },
    }
  tx_within_window(validity_range, window) == False
}

use aiken/collection/list
