/// Datum que almacena el hash del dueño para el handler spend.
pub type SpendDatum {
  owner: ByteArray,
}

/// Redeemer genérico para ambos handlers.
pub type Action {
  /// Para gastar un UTxO.
  SpendAction
  /// Para publicar un certificado.
  PublishAction
}

validator multi_handler(authorized_key: ByteArray) {
  /// Handler spend: verifica que el dueño firmó la transacción.
  spend(
    datum: Option<SpendDatum>,
    _redeemer: Action,
    _output_reference: Data,
    self: Transaction,
  ) -> Bool {
    when datum is {
      Some(d) ->
        list.has(self.extra_signatories, d.owner)
      None -> fail @"Datum ausente: se requiere el datum con el owner."
    }
  }

  /// Handler publish: verifica el tipo de certificado y la firma autorizada.
  publish(
    _redeemer: Action,
    cert: Certificate,
    self: Transaction,
  ) -> Bool {
    // Primero verificamos que la clave autorizada haya firmado.
    let is_signed = list.has(self.extra_signatories, authorized_key)

    // Luego verificamos que el certificado sea de un tipo permitido.
    let is_valid_cert =
      when cert is {
        RegisterCredential { credential: _, deposit: _ } -> True
        UnregisterCredential { credential: _, refund: _ } -> True
        DelegateCredential { credential: _, delegate: _ } -> True
        _ -> False
      }

    // Ambas condiciones deben cumplirse.
    and {
      is_signed?,
      is_valid_cert?,
    }
  }

  // Fallback obligatorio para cualquier otro propósito.
  else(_) {
    fail @"Propósito no soportado por este validador."
  }
}

