use aiken/collection/pairs
use cardano/governance.{ProposalProcedure}
use cardano/transaction.{InlineDatum, Transaction}

/// The datum holds the maximum allowed treasury withdrawal in lovelace.
pub type TreasuryCapDatum {
  max_withdrawal_lovelace: Int,
}

/// Redeemer is unit — no additional info needed.
pub type ProposeRedeemer {
  /// Marker to ensure we're checking the cap
  CheckCap
}

validator treasury_cap {
  propose(
    redeemer: ProposeRedeemer,
    proposal: ProposalProcedure,
    self: Transaction,
  ) -> Bool {
    when redeemer is {
      CheckCap -> {
        let max_cap = get_treasury_cap(self)

        let total_withdrawn = compute_total_treasury_withdrawals(self)

        let all_individual_ok = check_individual_withdrawals(self, max_cap)

        let total_ok = total_withdrawn <= max_cap

        let deposit_ok = proposal.deposit >= 0

        all_individual_ok && total_ok && deposit_ok
      }
    }
  }

  else(_) {
    fail
  }
}

/// Extracts the treasury cap from reference inputs.
fn get_treasury_cap(tx: Transaction) -> Int {
  when tx.reference_inputs is {
    [ref_input, ..] ->
      when ref_input.output.datum is {
        InlineDatum(raw_datum) -> {
          expect cap_datum: TreasuryCapDatum = raw_datum
          cap_datum.max_withdrawal_lovelace
        }
        _ ->
          fail @"Reference input must have an inline datum with treasury cap"
      }
    [] -> fail @"No reference input found containing the treasury cap datum"
  }
}

/// Computes the total lovelace across all treasury withdrawals.
fn compute_total_treasury_withdrawals(tx: Transaction) -> Int {
  tx.withdrawals
    |> pairs.foldl(0, fn(_credential, amount, acc) { acc + amount })
}

/// Checks that every individual treasury withdrawal is within the cap.
fn check_individual_withdrawals(tx: Transaction, max_cap: Int) -> Bool {
  tx.withdrawals
    |> pairs.foldl(
        True,
        fn(_credential, amount, acc) { acc && amount <= max_cap },
      )
}

test compute_total_treasury_withdrawals_empty() {
  let withdrawals: Pairs<ByteArray, Int> = []
  pairs.foldl(withdrawals, 0, fn(_credential, amount, acc) { acc + amount }) == 0
}

