validator admin_propose(admin_vkh: ByteArray) {
  propose(_redeemer: Data, proposal: ProposalProcedure, self: Transaction) -> Bool {
    // Check that the proposal is a ProtocolParameters governance action.
    // ProposalProcedure has a `governance_action` field.
    // We pattern match to ensure it's a parameter change, then require admin signature.
    when proposal.governance_action is {
      governance.ProtocolParameters { .. } -> {
        // The admin key must be present in the transaction's extra signatories
        list.has(self.extra_signatories, admin_vkh)
      }
      // Reject all other governance action types from this script
      _ -> fail @"Only protocol parameter change proposals are allowed through this validator"
