use aiken/collection/list
use aiken/interval.{Finite, Interval, IntervalBound}
use cardano/governance.{ProposalProcedure}
use cardano/transaction.{Transaction}

/// Datum that defines the allowed time window for proposals
pub type ProposalWindowDatum {
  /// The earliest POSIX time (in milliseconds) at which proposals are allowed
  window_start: Int,
  /// The latest POSIX time (in milliseconds) at which proposals are allowed
  window_end: Int,
}

validator proposal_time_window {
  propose(
    datum: ProposalWindowDatum,
    _proposal: ProposalProcedure,
    self: Transaction,
  ) -> Bool {
    let ProposalWindowDatum { window_start, window_end } = datum

    // Extract the validity range from the transaction
    let Interval {
      lower_bound: IntervalBound { bound_type: lower_bound_type, .. },
      upper_bound: IntervalBound { bound_type: upper_bound_type, .. },
    } = self.validity_range

    // The transaction's validity range must be fully contained within the window.
    // Lower bound must be at or after window_start
    let lower_ok =
      when lower_bound_type is {
        Finite(lower_time) -> lower_time >= window_start
        _ -> False
      }

    // Upper bound must be at or before window_end
    let upper_ok =
      when upper_bound_type is {
        Finite(upper_time) -> upper_time <= window_end
        _ -> False
      }

    // Window must be valid (start <= end)
    let valid_window = window_start <= window_end

    // All conditions must hold
    and {
      valid_window?,
      lower_ok?,
      upper_ok?,
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/governance.{ProposalProcedure}
use cardano/transaction.{Transaction}

/// The 5 committee member verification key hashes.
/// In production, replace these with actual key hashes.
const committee_member_1: ByteArray =
  #"00000000000000000000000000000000000000000000000000000001"

const committee_member_2: ByteArray =
  #"00000000000000000000000000000000000000000000000000000002"

const committee_member_3: ByteArray =
  #"00000000000000000000000000000000000000000000000000000003"

const committee_member_4: ByteArray =
  #"00000000000000000000000000000000000000000000000000000004"

const committee_member_5: ByteArray =
  #"00000000000000000000000000000000000000000000000000000005"

/// Minimum number of committee signatures required.
const required_signatures: Int = 3

/// Returns the list of all 5 committee member key hashes.
fn committee_members() -> List<ByteArray> {
  [
    committee_member_1,
    committee_member_2,
    committee_member_3,
    committee_member_4,
    committee_member_5,
  ]
}

/// Counts how many committee members have signed the transaction.
fn count_committee_signatures(signatories: List<ByteArray>) -> Int {
  list.foldl(
    committee_members(),
    0,
    fn(member, acc) {
      if list.has(signatories, member) {
        acc + 1
      } else {
        acc
      }
    },
  )
}

validator multi_sig_propose {
  propose(_redeemer: Data, _proposal: ProposalProcedure, self: Transaction) -> Bool {
    let signature_count = count_committee_signatures(self.extra_signatories)

    // Require at least 3 out of 5 committee members to sign
    if signature_count >= required_signatures {
      True
    } else {
      trace @"Insufficient committee signatures: need at least 3 of 5"
      False
    }
  }

  else(_) {
    fail
  }
}

